-- ----------------------------
-- Table structure for coach_application
-- ----------------------------
DROP TABLE IF EXISTS `coach_application`;
CREATE TABLE `coach_application`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `user_id` bigint NOT NULL COMMENT '申请人用户ID',
  `specialty` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '擅长领域',
  `intro` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '自我介绍',
  `cert_files` json NULL COMMENT '资质证明(图片/文件URL数组)',
  `audit_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'PENDING' COMMENT '审核状态(PENDING/APPROVED/REJECTED)',
  `audit_remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '审核意见/驳回原因',
  `audited_by` bigint NULL DEFAULT NULL COMMENT '审核管理员ID',
  `audited_at` datetime NULL DEFAULT NULL COMMENT '审核时间',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_coach_application_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_coach_application_status`(`audit_status` ASC) USING BTREE,
  CONSTRAINT `fk_coach_application_user` FOREIGN KEY (`user_id`) REFERENCES `sys_user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '教练认证申请表(用户申请->管理员审核->成为教练)' ROW_FORMAT = Dynamic;

