-- ----------------------------
-- Table structure for coach_course
-- ----------------------------
DROP TABLE IF EXISTS `coach_course`;
CREATE TABLE `coach_course`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `coach_user_id` bigint NOT NULL COMMENT '教练用户ID',
  `title` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '课程名称',
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '课程类型',
  `duration_minutes` int NULL DEFAULT NULL COMMENT '时长(分钟)',
  `price` int NOT NULL COMMENT '价格(整数金额)',
  `venue_id` bigint NULL DEFAULT NULL COMMENT '上课场地(可选)',
  `capacity` int NOT NULL DEFAULT 1 COMMENT '招生人数',
  `outline` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '课程大纲',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'ON_SALE' COMMENT '状态(ON_SALE/OFF_SALE)',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `cover_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_course_coach_user_id`(`coach_user_id` ASC) USING BTREE,
  INDEX `fk_course_venue`(`venue_id` ASC) USING BTREE,
  CONSTRAINT `fk_course_coach` FOREIGN KEY (`coach_user_id`) REFERENCES `sys_user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_course_venue` FOREIGN KEY (`venue_id`) REFERENCES `venue` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '教练课程' ROW_FORMAT = Dynamic;

