-- ----------------------------
-- Table structure for coach_course_booking
-- ----------------------------
DROP TABLE IF EXISTS `coach_course_booking`;
CREATE TABLE `coach_course_booking`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `booking_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '预约单号',
  `user_id` bigint NOT NULL COMMENT '预约用户ID',
  `course_session_id` bigint NOT NULL COMMENT '课程排期ID',
  `amount` int NOT NULL COMMENT '金额(整数金额)',
  `status` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'PENDING_COACH' COMMENT '状态(PENDING_COACH/ACCEPTED/REJECTED/PAID/CANCELED/REFUNDED/USED)',
  `coach_decision_at` datetime NULL DEFAULT NULL COMMENT '教练处理时间',
  `reject_reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '拒单原因',
  `verification_code` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '核销码',
  `paid_at` datetime NULL DEFAULT NULL COMMENT '支付时间(钱包扣款)',
  `used_at` datetime NULL DEFAULT NULL COMMENT '核销时间',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_course_booking_no`(`booking_no` ASC) USING BTREE,
  INDEX `idx_course_booking_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_course_booking_session_id`(`course_session_id` ASC) USING BTREE,
  INDEX `idx_course_booking_status`(`status` ASC) USING BTREE,
  CONSTRAINT `fk_course_booking_session` FOREIGN KEY (`course_session_id`) REFERENCES `coach_course_session` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_course_booking_user` FOREIGN KEY (`user_id`) REFERENCES `sys_user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 9 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '课程预约' ROW_FORMAT = Dynamic;

