-- ----------------------------
-- Table structure for coach_course_session
-- ----------------------------
DROP TABLE IF EXISTS `coach_course_session`;
CREATE TABLE `coach_course_session`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `course_id` bigint NOT NULL COMMENT '课程ID',
  `start_time` datetime NOT NULL COMMENT '开始时间',
  `end_time` datetime NOT NULL COMMENT '结束时间',
  `capacity` int NOT NULL COMMENT '容量',
  `enrolled_count` int NOT NULL DEFAULT 0 COMMENT '已报名人数',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'OPEN' COMMENT '状态(OPEN/CLOSED/CANCELED)',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_course_session_course_id`(`course_id` ASC) USING BTREE,
  INDEX `idx_course_session_time`(`start_time` ASC) USING BTREE,
  CONSTRAINT `fk_course_session_course` FOREIGN KEY (`course_id`) REFERENCES `coach_course` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 5 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '课程排期' ROW_FORMAT = Dynamic;

