DROP TABLE IF EXISTS `complaint`;
CREATE TABLE `complaint`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `complaint_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '投诉单号',
  `user_id` bigint NOT NULL COMMENT '投诉用户ID',
  `complaint_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '类型(VENUE/EQUIPMENT/COURSE/OTHER)',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '投诉内容',
  `attachments` json NULL COMMENT '附件(图片/文件URL数组)',
  `status` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'SUBMITTED' COMMENT '状态(SUBMITTED/ASSIGNED/IN_PROGRESS/RESOLVED)',
  `assigned_staff_id` bigint NULL DEFAULT NULL COMMENT '指派员工ID',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `resolved_at` datetime NULL DEFAULT NULL COMMENT '完成时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_complaint_no`(`complaint_no` ASC) USING BTREE,
  INDEX `idx_complaint_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_complaint_status`(`status` ASC) USING BTREE,
  INDEX `fk_complaint_staff`(`assigned_staff_id` ASC) USING BTREE,
  CONSTRAINT `fk_complaint_staff` FOREIGN KEY (`assigned_staff_id`) REFERENCES `sys_user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_complaint_user` FOREIGN KEY (`user_id`) REFERENCES `sys_user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 3 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '投诉工单' ROW_FORMAT = Dynamic;

