-- Table structure for staff_inspection_report
-- ----------------------------
DROP TABLE IF EXISTS `staff_inspection_report`;
CREATE TABLE `staff_inspection_report`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `staff_user_id` bigint NOT NULL COMMENT '员工用户ID',
  `region` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '负责区域(快照)',
  `target_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '关联对象类型(VENUE/EQUIPMENT/OTHER)',
  `venue_id` bigint NULL DEFAULT NULL COMMENT '场地ID(target_type=VENUE)',
  `equipment_id` bigint NULL DEFAULT NULL COMMENT '器材ID(target_type=EQUIPMENT)',
  `issue_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '问题类型(MAINTENANCE/REPAIR/SHORTAGE/DAMAGE/OTHER)',
  `content` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '上报内容',
  `attachments` varchar(2000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '附件URL数组(JSON)',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '状态(SUBMITTED/IN_PROGRESS/RESOLVED)',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `resolved_at` datetime NULL DEFAULT NULL COMMENT '解决时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_staff_created_at`(`staff_user_id` ASC, `created_at` ASC) USING BTREE,
  INDEX `idx_region`(`region` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '员工巡检/维护上报表' ROW_FORMAT = Dynamic;

