-- ----------------------------
-- Table structure for venue_booking
-- ----------------------------
DROP TABLE IF EXISTS `venue_booking`;
CREATE TABLE `venue_booking`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `booking_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '预约单号',
  `user_id` bigint NOT NULL COMMENT '预约用户ID',
  `venue_id` bigint NOT NULL COMMENT '场地ID',
  `timeslot_id` bigint NOT NULL COMMENT '预约时段ID',
  `amount` int NOT NULL COMMENT '应付金额(整数金额)',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'CREATED' COMMENT '状态(CREATED/PAID/CANCELED/REFUNDED/USED)',
  `verification_code` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '核销码',
  `paid_at` datetime NULL DEFAULT NULL COMMENT '支付时间(钱包扣款)',
  `canceled_at` datetime NULL DEFAULT NULL COMMENT '取消时间',
  `used_at` datetime NULL DEFAULT NULL COMMENT '核销时间',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_venue_booking_no`(`booking_no` ASC) USING BTREE,
  UNIQUE INDEX `uk_venue_booking_timeslot`(`timeslot_id` ASC) USING BTREE,
  INDEX `idx_venue_booking_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_venue_booking_status`(`status` ASC) USING BTREE,
  INDEX `fk_venue_booking_venue`(`venue_id` ASC) USING BTREE,
  CONSTRAINT `fk_venue_booking_timeslot` FOREIGN KEY (`timeslot_id`) REFERENCES `venue_timeslot` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_venue_booking_user` FOREIGN KEY (`user_id`) REFERENCES `sys_user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_venue_booking_venue` FOREIGN KEY (`venue_id`) REFERENCES `venue` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '场地预约单' ROW_FORMAT = Dynamic;

