-- ----------------------------
-- Table structure for venue_timeslot
-- ----------------------------
DROP TABLE IF EXISTS `venue_timeslot`;
CREATE TABLE `venue_timeslot`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `venue_id` bigint NOT NULL COMMENT '场地ID',
  `start_time` datetime NOT NULL COMMENT '开始时间',
  `end_time` datetime NOT NULL COMMENT '结束时间',
  `price` int NOT NULL COMMENT '该时段价格(整数金额)',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'AVAILABLE' COMMENT '状态(AVAILABLE/BOOKED/BLOCKED)',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_venue_timeslot`(`venue_id` ASC, `start_time` ASC, `end_time` ASC) USING BTREE,
  INDEX `idx_venue_timeslot_status`(`status` ASC) USING BTREE,
  CONSTRAINT `fk_venue_timeslot_venue` FOREIGN KEY (`venue_id`) REFERENCES `venue` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 6366 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '场地可预约时段' ROW_FORMAT = Dynamic;

