-- ----------------------------
-- Table structure for venue_verification_log
-- ----------------------------
DROP TABLE IF EXISTS `venue_verification_log`;
CREATE TABLE `venue_verification_log`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `booking_id` bigint NOT NULL COMMENT '预约单ID',
  `staff_user_id` bigint NOT NULL COMMENT '核销员工ID',
  `verified_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '核销时间',
  `result` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '结果(SUCCESS/FAILED)',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_venue_verify_booking_id`(`booking_id` ASC) USING BTREE,
  INDEX `fk_venue_verify_staff`(`staff_user_id` ASC) USING BTREE,
  CONSTRAINT `fk_venue_verify_booking` FOREIGN KEY (`booking_id`) REFERENCES `venue_booking` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_venue_verify_staff` FOREIGN KEY (`staff_user_id`) REFERENCES `sys_user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '场地核销记录' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of venue_verification_log
-- ----------------------------
INSERT INTO `venue_verification_log` VALUES (1, 2, 1, '2025-12-24 11:23:53', 'SUCCESS', NULL);

-- ----------------------------
-- Table structure for wallet_account
-- ----------------------------
DROP TABLE IF EXISTS `wallet_account`;
CREATE TABLE `wallet_account`  (
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `balance` int NOT NULL DEFAULT 0 COMMENT '钱包余额(整数金额)',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`user_id`) USING BTREE,
  CONSTRAINT `fk_wallet_account_user` FOREIGN KEY (`user_id`) REFERENCES `sys_user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '钱包账户表' ROW_FORMAT = Dynamic;

