DROP TABLE IF EXISTS `wallet_topup_request`;
CREATE TABLE `wallet_topup_request`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `request_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '申请单号',
  `user_id` bigint NOT NULL COMMENT '申请人用户ID(用户/教练/员工)',
  `amount` int NOT NULL COMMENT '申请金额(1-9999)',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'PENDING' COMMENT '状态(PENDING/APPROVED/REJECTED)',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '申请说明/管理员备注',
  `requested_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '申请时间',
  `processed_by` bigint NULL DEFAULT NULL COMMENT '处理管理员ID',
  `processed_at` datetime NULL DEFAULT NULL COMMENT '处理时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_wallet_topup_request_no`(`request_no` ASC) USING BTREE,
  INDEX `idx_wallet_topup_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_wallet_topup_status`(`status` ASC) USING BTREE,
  CONSTRAINT `fk_wallet_topup_user` FOREIGN KEY (`user_id`) REFERENCES `sys_user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 3 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '钱包充值申请(管理员审核发放)' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of wallet_topup_request
-- ----------------------------
INSERT INTO `wallet_topup_request` VALUES (1, '05ff0f47d3944228bc57007a54bc0c2d', 3, 200, 'APPROVED', '审核通过', '2025-12-24 13:39:55', 1, '2025-12-24 13:40:43');
